// 8-fold symmery
__device__
static int _fill_jk_tasks(ShellQuartet *shl_quartet_idx,
                          RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                          int batch_ij, int batch_kl)
{
    int nbas = envs.nbas;
    int *tile_ij_mapping = bounds.tile_ij_mapping;
    int *tile_kl_mapping = bounds.tile_kl_mapping;
    float *q_cond = bounds.q_cond;
    float *tile_q_cond = bounds.tile_q_cond;
    float *dm_cond = bounds.dm_cond;
    float cutoff = bounds.cutoff;
    int t_id = threadIdx.y * blockDim.x + threadIdx.x;
    int t_kl0 = batch_kl * TILES_IN_BATCH;
    int t_kl1 = MIN(t_kl0 + TILES_IN_BATCH, bounds.ntile_kl_pairs);
    int threads = blockDim.x * blockDim.y;

    int tile_ij = tile_ij_mapping[batch_ij];
    int nbas_tiles = nbas / TILE;
    int tile_i = tile_ij / nbas_tiles;
    int tile_j = tile_ij % nbas_tiles;
    int ish0 = tile_i * TILE;
    int jsh0 = tile_j * TILE;
    int ish1 = ish0 + TILE;
    int jsh1 = jsh0 + TILE;
    int do_j = jk.vj != NULL;
    int do_k = jk.vk != NULL;

    int count = 0;
    float tile_q_ij = tile_q_cond[tile_ij];
    for (int t_kl_id = t_kl0+t_id; t_kl_id < t_kl1; t_kl_id += threads) {
        int tile_kl = tile_kl_mapping[t_kl_id];
        if (tile_q_ij + tile_q_cond[tile_kl] < cutoff) {
            break;
        }
        int tile_k = tile_kl / nbas_tiles;
        int tile_l = tile_kl % nbas_tiles;
        int ksh0 = tile_k * TILE;
        int lsh0 = tile_l * TILE;
        int ksh1 = ksh0 + TILE;
        int lsh1 = lsh0 + TILE;
        for (int ish = ish0; ish < ish1; ++ish) {
            for (int jsh = jsh0; jsh < MIN(ish+1, jsh1); ++jsh) {
                int bas_ij = ish * nbas + jsh;
                float q_ij = q_cond [bas_ij];
                float d_ij = dm_cond[bas_ij];
                for (int ksh = ksh0; ksh < MIN(ish+1, ksh1); ++ksh) {
                    float d_ik = dm_cond[ish*nbas+ksh];
                    float d_jk = dm_cond[jsh*nbas+ksh];
                    for (int lsh = lsh0; lsh < MIN(ksh+1, lsh1); ++lsh) {
                        int bas_kl = ksh * nbas + lsh;
                        if (bas_ij < bas_kl) {
                            continue;
                        }
                        float q_ijkl = q_ij + q_cond[bas_kl];
                        if (q_ijkl < cutoff) {
                            continue;
                        }
                        float d_cutoff = cutoff - q_ijkl;
                        if ((do_k && (d_ik                  > d_cutoff ||
                                      d_jk                  > d_cutoff ||
                                      dm_cond[ish*nbas+lsh] > d_cutoff ||
                                      dm_cond[jsh*nbas+lsh] > d_cutoff)) ||
                            (do_j && (d_ij                  > d_cutoff ||
                                      dm_cond[bas_kl      ] > d_cutoff))) {
                            ++count;
                        }
                    }
                }
            }
        }
    }

    // https://developer.nvidia.com/gpugems/gpugems3/part-vi-gpu-computing/chapter-39-parallel-prefix-sum-scan-cuda
    extern __shared__ int cum_count[];
    cum_count[t_id] = count;
    // Up-sweep phase
    for (int stride = 1; stride < threads; stride *= 2) {
        __syncthreads();
        int index = (t_id + 1) * stride * 2 - 1;
        if (index < threads) {
            cum_count[index] += cum_count[index-stride];
        }
    }
    __syncthreads();
    // Down-sweep phase
    for (int stride = threads/4; stride > 0; stride /= 2) {
        __syncthreads();
        int index = (t_id + 1) * stride * 2 - 1;
        if (index + stride < threads) {
            cum_count[index + stride] += cum_count[index];
        }
    }
    __syncthreads();
    int ntasks = cum_count[threads-1];
    if (ntasks == 0) {
        return ntasks;
    }

    int offset = 0;
    if (t_id > 0) {
        offset = cum_count[t_id-1];
    }
    for (int t_kl_id = t_kl0+t_id; t_kl_id < t_kl1; t_kl_id += threads) {
        int tile_kl = tile_kl_mapping[t_kl_id];
        if (tile_q_ij + tile_q_cond[tile_kl] < cutoff) {
            break;
        }
        int tile_k = tile_kl / nbas_tiles;
        int tile_l = tile_kl % nbas_tiles;
        int ksh0 = tile_k * TILE;
        int lsh0 = tile_l * TILE;
        int ksh1 = ksh0 + TILE;
        int lsh1 = lsh0 + TILE;
        ShellQuartet sq;
        for (int ish = ish0; ish < ish1; ++ish) {
            for (int jsh = jsh0; jsh < MIN(ish+1, jsh1); ++jsh) {
                int bas_ij = ish * nbas + jsh;
                float q_ij = q_cond [bas_ij];
                float d_ij = dm_cond[bas_ij];
                sq.i = ish;
                sq.j = jsh;
                for (int ksh = ksh0; ksh < MIN(ish+1, ksh1); ++ksh) {
                    float d_ik = dm_cond[ish*nbas+ksh];
                    float d_jk = dm_cond[jsh*nbas+ksh];
                    for (int lsh = lsh0; lsh < MIN(ksh+1, lsh1); ++lsh) {
                        int bas_kl = ksh * nbas + lsh;
                        if (bas_ij < bas_kl) {
                            continue;
                        }
                        float q_ijkl = q_ij + q_cond[bas_kl];
                        if (q_ijkl < cutoff) {
                            continue;
                        }
                        float d_cutoff = cutoff - q_ijkl;
                        if ((do_k && (d_ik                  > d_cutoff ||
                                      d_jk                  > d_cutoff ||
                                      dm_cond[ish*nbas+lsh] > d_cutoff ||
                                      dm_cond[jsh*nbas+lsh] > d_cutoff)) ||
                            (do_j && (d_ij                  > d_cutoff ||
                                      dm_cond[bas_kl      ] > d_cutoff))) {
                            sq.k = ksh;
                            sq.l = lsh;
                            shl_quartet_idx[offset] = sq;
                            ++offset;
                        }
                    }
                }
            }
        }
    }
    return ntasks;
}

// 8-fold symmery
__device__
static int _fill_sr_jk_tasks(ShellQuartet *shl_quartet_idx,
                             RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                             int batch_ij, int batch_kl)
{
    int nbas = envs.nbas;
    int *tile_ij_mapping = bounds.tile_ij_mapping;
    int *tile_kl_mapping = bounds.tile_kl_mapping;
    float *q_cond = bounds.q_cond;
    float *tile_q_cond = bounds.tile_q_cond;
    int nbas_tiles = nbas / TILE;
    // TODO: implement q_ijij_cond
    float *s_estimator = bounds.s_estimator;
    float *dm_cond = bounds.dm_cond;
    float cutoff = bounds.cutoff;
    int t_id = threadIdx.y * blockDim.x + threadIdx.x;
    int t_kl0 = batch_kl * TILES_IN_BATCH;
    int t_kl1 = MIN(t_kl0 + TILES_IN_BATCH, bounds.ntile_kl_pairs);
    int threads = blockDim.x * blockDim.y;

    int tile_ij = tile_ij_mapping[batch_ij];
    int tile_i = tile_ij / nbas_tiles;
    int tile_j = tile_ij % nbas_tiles;
    int ish0 = tile_i * TILE;
    int jsh0 = tile_j * TILE;
    int ish1 = ish0 + TILE;
    int jsh1 = jsh0 + TILE;
    int do_j = jk.vj != NULL;
    int do_k = jk.vk != NULL;

    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    int kprim = bounds.kprim;
    int lprim = bounds.lprim;
    int *bas = envs.bas;
    double *env = envs.env;
    float omega = env[PTR_RANGE_OMEGA];
    float omega2 = omega * omega;

    int count = 0;
    float tile_q_ij = tile_q_cond[tile_ij];
    for (int t_kl_id = t_kl0+t_id; t_kl_id < t_kl1; t_kl_id += threads) {
        int tile_kl = tile_kl_mapping[t_kl_id];
        if (tile_q_ij + tile_q_cond[tile_kl] < cutoff) {
            break;
        }
        int tile_k = tile_kl / nbas_tiles;
        int tile_l = tile_kl % nbas_tiles;
        int ksh0 = tile_k * TILE;
        int lsh0 = tile_l * TILE;
        int ksh1 = ksh0 + TILE;
        int lsh1 = lsh0 + TILE;
        for (int ish = ish0; ish < ish1; ++ish) {
            for (int jsh = jsh0; jsh < MIN(ish+1, jsh1); ++jsh) {
                double *expi = env + bas[ish*BAS_SLOTS+PTR_EXP];
                double *expj = env + bas[jsh*BAS_SLOTS+PTR_EXP];
                double *ri = env + bas[ish*BAS_SLOTS+PTR_BAS_COORD];
                double *rj = env + bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
                float ai = expi[iprim-1];
                float aj = expj[jprim-1];
                float aij = ai + aj;
                float aj_aij = aj / aij;
                float xi = ri[0];
                float yi = ri[1];
                float zi = ri[2];
                float xj = rj[0];
                float yj = rj[1];
                float zj = rj[2];
                float xjxi = xj - xi;
                float yjyi = yj - yi;
                float zjzi = zj - zi;
                float xpa = xjxi * aj_aij;
                float ypa = yjyi * aj_aij;
                float zpa = zjzi * aj_aij;
                float xij = xi + xpa;
                float yij = yi + ypa;
                float zij = zi + zpa;
                int bas_ij = ish * nbas + jsh;
                float q_ij = q_cond [bas_ij];
                float d_ij = dm_cond[bas_ij];
                float skl_cutoff = cutoff - s_estimator[bas_ij];
                for (int ksh = ksh0; ksh < MIN(ish+1, ksh1); ++ksh) {
                    float d_ik = dm_cond[ish*nbas+ksh];
                    float d_jk = dm_cond[jsh*nbas+ksh];
                    for (int lsh = lsh0; lsh < MIN(ksh+1, lsh1); ++lsh) {
                        int bas_kl = ksh * nbas + lsh;
                        if (bas_ij < bas_kl) {
                            continue;
                        }
                        float q_ijkl = q_ij + q_cond[bas_kl];
                        if (q_ijkl < cutoff) {
                            continue;
                        }
                        float d_cutoff = cutoff - q_ijkl;
                        if ((do_k && (d_ik                  > d_cutoff ||
                                      d_jk                  > d_cutoff ||
                                      dm_cond[ish*nbas+lsh] > d_cutoff ||
                                      dm_cond[jsh*nbas+lsh] > d_cutoff)) ||
                            (do_j && (d_ij                  > d_cutoff ||
                                      dm_cond[bas_kl      ] > d_cutoff))) {

                            double *expk = env + bas[ksh*BAS_SLOTS+PTR_EXP];
                            double *expl = env + bas[lsh*BAS_SLOTS+PTR_EXP];
                            double *rk = env + bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
                            double *rl = env + bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
                            float ak = expk[kprim-1];
                            float al = expl[lprim-1];
                            float akl = ak + al;
                            float al_akl = al / akl;
                            float xk = rk[0];
                            float yk = rk[1];
                            float zk = rk[2];
                            float xl = rl[0];
                            float yl = rl[1];
                            float zl = rl[2];
                            float xlxk = xl - xk;
                            float ylyk = yl - yk;
                            float zlzk = zl - zk;
                            float xqc = xlxk * al_akl;
                            float yqc = ylyk * al_akl;
                            float zqc = zlzk * al_akl;
                            float xkl = xk + xqc;
                            float ykl = yk + yqc;
                            float zkl = zk + zqc;
                            float theta = 1./(1./aij+1./akl+1./omega2);
                            float xpq = xij - xkl;
                            float ypq = yij - ykl;
                            float zpq = zij - zkl;
                            float rr = xpq*xpq + ypq*ypq + zpq*zpq;
                            float theta_rr = logf(rr + 1.f) + theta * rr;
                            d_cutoff = skl_cutoff - s_estimator[bas_kl] + theta_rr;
                            if (d_cutoff > 0) {
                                continue;
                            }
                            if ((do_k && (d_ik                  > d_cutoff ||
                                          d_jk                  > d_cutoff ||
                                          dm_cond[ish*nbas+lsh] > d_cutoff ||
                                          dm_cond[jsh*nbas+lsh] > d_cutoff)) ||
                                (do_j && (d_ij                  > d_cutoff ||
                                          dm_cond[bas_kl      ] > d_cutoff))) {
                                ++count;
                            }
                        }
                    }
                }
            }
        }
    }

    // https://developer.nvidia.com/gpugems/gpugems3/part-vi-gpu-computing/chapter-39-parallel-prefix-sum-scan-cuda
    extern __shared__ int cum_count[];
    cum_count[t_id] = count;
    // Up-sweep phase
    for (int stride = 1; stride < threads; stride *= 2) {
        __syncthreads();
        int index = (t_id + 1) * stride * 2 - 1;
        if (index < threads) {
            cum_count[index] += cum_count[index-stride];
        }
    }
    __syncthreads();
    // Down-sweep phase
    for (int stride = threads/4; stride > 0; stride /= 2) {
        __syncthreads();
        int index = (t_id + 1) * stride * 2 - 1;
        if (index + stride < threads) {
            cum_count[index + stride] += cum_count[index];
        }
    }
    __syncthreads();
    int ntasks = cum_count[threads-1];
    if (ntasks == 0) {
        return ntasks;
    }

    int offset = 0;
    if (t_id > 0) {
        offset = cum_count[t_id-1];
    }
    for (int t_kl_id = t_kl0+t_id; t_kl_id < t_kl1; t_kl_id += threads) {
        int tile_kl = tile_kl_mapping[t_kl_id];
        if (tile_q_ij + tile_q_cond[tile_kl] < cutoff) {
            break;
        }
        int tile_k = tile_kl / nbas_tiles;
        int tile_l = tile_kl % nbas_tiles;
        int ksh0 = tile_k * TILE;
        int lsh0 = tile_l * TILE;
        int ksh1 = ksh0 + TILE;
        int lsh1 = lsh0 + TILE;
        ShellQuartet sq;
        for (int ish = ish0; ish < ish1; ++ish) {
            for (int jsh = jsh0; jsh < MIN(ish+1, jsh1); ++jsh) {
                sq.i = ish;
                sq.j = jsh;
                double *expi = env + bas[ish*BAS_SLOTS+PTR_EXP];
                double *expj = env + bas[jsh*BAS_SLOTS+PTR_EXP];
                double *ri = env + bas[ish*BAS_SLOTS+PTR_BAS_COORD];
                double *rj = env + bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
                float ai = expi[iprim-1];
                float aj = expj[jprim-1];
                float aij = ai + aj;
                float aj_aij = aj / aij;
                float xi = ri[0];
                float yi = ri[1];
                float zi = ri[2];
                float xj = rj[0];
                float yj = rj[1];
                float zj = rj[2];
                float xjxi = xj - xi;
                float yjyi = yj - yi;
                float zjzi = zj - zi;
                float xpa = xjxi * aj_aij;
                float ypa = yjyi * aj_aij;
                float zpa = zjzi * aj_aij;
                float xij = xi + xpa;
                float yij = yi + ypa;
                float zij = zi + zpa;
                int bas_ij = ish * nbas + jsh;
                float q_ij = q_cond [bas_ij];
                float d_ij = dm_cond[bas_ij];
                float skl_cutoff = cutoff - s_estimator[bas_ij];
                for (int ksh = ksh0; ksh < MIN(ish+1, ksh1); ++ksh) {
                    float d_ik = dm_cond[ish*nbas+ksh];
                    float d_jk = dm_cond[jsh*nbas+ksh];
                    for (int lsh = lsh0; lsh < MIN(ksh+1, lsh1); ++lsh) {
                        int bas_kl = ksh * nbas + lsh;
                        if (bas_ij < bas_kl) {
                            continue;
                        }
                        float q_ijkl = q_ij + q_cond[bas_kl];
                        if (q_ijkl < cutoff) {
                            continue;
                        }
                        float d_cutoff = cutoff - q_ijkl;
                        if ((do_k && (d_ik                  > d_cutoff ||
                                      d_jk                  > d_cutoff ||
                                      dm_cond[ish*nbas+lsh] > d_cutoff ||
                                      dm_cond[jsh*nbas+lsh] > d_cutoff)) ||
                            (do_j && (d_ij                  > d_cutoff ||
                                      dm_cond[bas_kl      ] > d_cutoff))) {

                            // TODO: cache in shared memory
                            double *expk = env + bas[ksh*BAS_SLOTS+PTR_EXP];
                            double *expl = env + bas[lsh*BAS_SLOTS+PTR_EXP];
                            double *rk = env + bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
                            double *rl = env + bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
                            float ak = expk[kprim-1];
                            float al = expl[lprim-1];
                            float akl = ak + al;
                            float al_akl = al / akl;
                            float xk = rk[0];
                            float yk = rk[1];
                            float zk = rk[2];
                            float xl = rl[0];
                            float yl = rl[1];
                            float zl = rl[2];
                            float xlxk = xl - xk;
                            float ylyk = yl - yk;
                            float zlzk = zl - zk;
                            float xqc = xlxk * al_akl;
                            float yqc = ylyk * al_akl;
                            float zqc = zlzk * al_akl;
                            float xkl = xk + xqc;
                            float ykl = yk + yqc;
                            float zkl = zk + zqc;
                            float theta = 1./(1./aij+1./akl+1./omega2);
                            float xpq = xij - xkl;
                            float ypq = yij - ykl;
                            float zpq = zij - zkl;
                            float rr = xpq*xpq + ypq*ypq + zpq*zpq;
                            float theta_rr = logf(rr + 1.f) + theta * rr;
                            d_cutoff = skl_cutoff - s_estimator[bas_kl] + theta_rr;
                            if (d_cutoff > 0) {
                                continue;
                            }
                            if ((do_k && (d_ik                  > d_cutoff ||
                                          d_jk                  > d_cutoff ||
                                          dm_cond[ish*nbas+lsh] > d_cutoff ||
                                          dm_cond[jsh*nbas+lsh] > d_cutoff)) ||
                                (do_j && (d_ij                  > d_cutoff ||
                                          dm_cond[bas_kl      ] > d_cutoff))) {
                                sq.k = ksh;
                                sq.l = lsh;
                                shl_quartet_idx[offset] = sq;
                                ++offset;
                            }
                        }
                    }
                }
            }
        }
    }
    return ntasks;
}


__device__
static void rys_roots(int nroots, double x, double *rw,
                      int block_size, int rt_id, int stride)
{
    double *r = rw;
    double *w = rw + block_size;
    int block_size2 = block_size * 2;
    if (x < 3.e-7){
        int off = nroots * (nroots - 1) / 2;
        for (int i = rt_id; i < nroots; i += stride)  {
            r[i*block_size2] = ROOT_SMALLX_R0[off+i] + ROOT_SMALLX_R1[off+i] * x;
            w[i*block_size2] = ROOT_SMALLX_W0[off+i] + ROOT_SMALLX_W1[off+i] * x;
        }
        return;
    }

    if (x > 35+nroots*5) {
        int off = nroots * (nroots - 1) / 2;
        double t = sqrt(PIE4/x);
        for (int i = rt_id; i < nroots; i += stride)  {
            r[i*block_size2] = ROOT_LARGEX_R_DATA[off+i] / x;
            w[i*block_size2] = ROOT_LARGEX_W_DATA[off+i] * t;
        }
        return;
    }

    if (nroots == 1) {
        double tt = sqrt(x);
        double fmt0 = SQRTPIE4 / tt * erf(tt);
        w[0] = fmt0;
        double e = exp(-x);
        double b = .5 / x;
        double fmt1 = b * (fmt0 - e);
        r[0] = fmt1 / fmt0;
        return;
    }

    double *datax = ROOT_RW_DATA + DEGREE1*INTERVALS * nroots*(nroots-1);
    int it = (int)(x * .4);
    double u = (x - it * 2.5) * 0.8 - 1.;
    double u2 = u * 2.;
    for (int i = rt_id; i < nroots*2; i += stride) {
        double *c = datax + i * DEGREE1 * INTERVALS;
        //for i in range(2, degree + 1):
        //    c0, c1 = c[degree-i] - c1, c0 + c1*u2
        double c0 = c[it + DEGREE   *INTERVALS];
        double c1 = c[it +(DEGREE-1)*INTERVALS];
        double c2, c3;
#pragma unroll
        for (int n = DEGREE-2; n > 0; n-=2) {
            c2 = c[it + n   *INTERVALS] - c1;
            c3 = c0 + c1*u2;
            c1 = c2 + c3*u2;
            c0 = c[it +(n-1)*INTERVALS] - c3;
        }
        if (DEGREE % 2 == 0) {
            c2 = c[it] - c1;
            c3 = c0 + c1*u2;
            rw[i*block_size] = c2 + c3*u;
        } else {
            rw[i*block_size] = c0 + c1*u;
        }
    }
}

// rys_roots for range-separation Coulomb
__device__
static void rys_roots_rs(int nroots, double theta, double rr, double omega,
                         double *rw, int block_size, int rt_id, int stride)
{
    double theta_rr = theta * rr;
    if (omega == 0) {
        rys_roots(nroots, theta_rr, rw, block_size, rt_id, stride);
    } else if (omega > 0) {
        double theta_fac = omega * omega / (omega * omega + theta);
        rys_roots(nroots, theta_fac*theta_rr, rw, block_size, rt_id, stride);
        __syncthreads();
        double sqrt_theta_fac = sqrt(theta_fac);
        for (int irys = rt_id; irys < nroots; irys+=stride) {
            rw[ irys*2   *block_size] *= theta_fac;
            rw[(irys*2+1)*block_size] *= sqrt_theta_fac;
        }
    } else {
        int _nroots = nroots / 2;
        double *rw1 = rw + nroots*block_size;
        rys_roots(_nroots, theta_rr, rw1, block_size, rt_id, stride);
        double theta_fac = omega * omega / (omega * omega + theta);
        rys_roots(_nroots, theta_fac*theta_rr, rw, block_size, rt_id, stride);
        __syncthreads();
        double sqrt_theta_fac = -sqrt(theta_fac);
        for (int irys = rt_id; irys < _nroots; irys+=stride) {
            rw[ irys*2   *block_size] *= theta_fac;
            rw[(irys*2+1)*block_size] *= sqrt_theta_fac;
        }
    }
}

__device__
static void rys_jk_general(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                           ShellQuartet *shl_quartet_idx, int ntasks)
{
    // sq is short for shl_quartet
    int sq_id = threadIdx.x;
    int nsq_per_block = blockDim.x;
    int gout_id = threadIdx.y;
    int gout_stride = blockDim.y;
    int li = bounds.li;
    int lj = bounds.lj;
    int lk = bounds.lk;
    int ll = bounds.ll;
    int nfi = bounds.nfi;
    int nfj = (lj + 1) * (lj + 2) / 2;
    int nfk = bounds.nfk;
    int nfl = (ll + 1) * (ll + 2) / 2;
    int nfij = bounds.nfij;
    int nfkl = bounds.nfkl;
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    int kprim = bounds.kprim;
    int lprim = bounds.lprim;
    int lij = li + lj;
    int lkl = lk + ll;
    int nroots = bounds.nroots;
    int stride_j = bounds.stride_j;
    int stride_k = bounds.stride_k;
    int stride_l = bounds.stride_l;
    int g_size = stride_l * (ll + 1);
    int *idx_ij = c_g_pair_idx + c_g_pair_offsets[li*LMAX1+lj];
    int *idy_ij = idx_ij + nfij;
    int *idz_ij = idy_ij + nfij;
    int *idx_kl = c_g_pair_idx + c_g_pair_offsets[lk*LMAX1+ll];
    int *idy_kl = idx_kl + nfkl;
    int *idz_kl = idy_kl + nfkl;
    int *bas = envs.bas;
    int *ao_loc = envs.ao_loc;
    int nbas = envs.nbas;
    int nao = ao_loc[nbas];
    //double *env = c_env;
    double *env = envs.env;
    double omega = env[PTR_RANGE_OMEGA];

    extern __shared__ double shared_memory[];
    double *rjri = shared_memory + sq_id;
    double *rlrk = rjri + nsq_per_block * 3;
    double *Rpq = rlrk + nsq_per_block * 3;
    double *cicj_cache = Rpq + nsq_per_block * 3;
    double *rw = cicj_cache + nsq_per_block * iprim * jprim;
    double *g = rw + nsq_per_block * nroots * 2;
    double *gx = g;
    double *gy = g + nsq_per_block * g_size;
    double *gz = gy + nsq_per_block * g_size;

    double gout[GOUT_WIDTH];

    for (int task0 = 0; task0 < ntasks; task0 += nsq_per_block) {
        __syncthreads();
        int task_id = task0 + sq_id;
        double fac_sym = PI_FAC;
        ShellQuartet sq;
        if (task_id >= ntasks) {
            // To avoid __syncthreads blocking blocking idle warps, all remaining
            // threads compute a valid shell quartet with zero normalization factor
            sq = shl_quartet_idx[0];
            fac_sym = 0.;
        } else {
            sq = shl_quartet_idx[task_id];
        }
        int ish = sq.i;
        int jsh = sq.j;
        int ksh = sq.k;
        int lsh = sq.l;
        //int sh_ij = (ish % TILE) * TILE + (jsh % TILE);
        if (ish == jsh) fac_sym *= .5;
        if (ksh == lsh) fac_sym *= .5;
        if (ish*nbas+jsh == ksh*nbas+lsh) fac_sym *= .5;
        int i0 = ao_loc[ish];
        int j0 = ao_loc[jsh];
        int k0 = ao_loc[ksh];
        int l0 = ao_loc[lsh];
        double *expi = env + bas[ish*BAS_SLOTS+PTR_EXP];
        double *expj = env + bas[jsh*BAS_SLOTS+PTR_EXP];
        double *expk = env + bas[ksh*BAS_SLOTS+PTR_EXP];
        double *expl = env + bas[lsh*BAS_SLOTS+PTR_EXP];
        double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
        double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
        double *ck = env + bas[ksh*BAS_SLOTS+PTR_COEFF];
        double *cl = env + bas[lsh*BAS_SLOTS+PTR_COEFF];
        double *ri = env + bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        double *rj = env + bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        double *rk = env + bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        double *rl = env + bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        double xjxi = rj[0] - ri[0];
        double yjyi = rj[1] - ri[1];
        double zjzi = rj[2] - ri[2];
        double rr_ij = xjxi*xjxi + yjyi*yjyi + zjzi*zjzi;
        if (gout_id == 0) {
            double xlxk = rl[0] - rk[0];
            double ylyk = rl[1] - rk[1];
            double zlzk = rl[2] - rk[2];
            rjri[0*nsq_per_block] = xjxi;
            rjri[1*nsq_per_block] = yjyi;
            rjri[2*nsq_per_block] = zjzi;
            rlrk[0*nsq_per_block] = xlxk;
            rlrk[1*nsq_per_block] = ylyk;
            rlrk[2*nsq_per_block] = zlzk;
        }
        for (int ij = gout_id; ij < iprim*jprim; ij += gout_stride) {
            int ip = ij / jprim;
            int jp = ij % jprim;
            double ai = expi[ip];
            double aj = expj[jp];
            double aij = ai + aj;
            double theta_ij = ai * aj / aij;
            double Kab = exp(-theta_ij * rr_ij);
            cicj_cache[ij*nsq_per_block] = fac_sym * ci[ip] * cj[jp] * Kab;
        }
        for (int gout_start = 0; gout_start < nfij*nfkl; gout_start+=gout_stride*GOUT_WIDTH) {
#pragma unroll
        for (int n = 0; n < GOUT_WIDTH; ++n) { gout[n] = 0; }

        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = expk[kp];
            double al = expl[lp];
            double akl = ak + al;
            double al_akl = al / akl;
            __syncthreads();
            if (gout_id == 0) {
                double xlxk = rlrk[0*nsq_per_block];
                double ylyk = rlrk[1*nsq_per_block];
                double zlzk = rlrk[2*nsq_per_block];
                double rr_kl = xlxk*xlxk + ylyk*ylyk + zlzk*zlzk;
                double theta_kl = ak * al / akl;
                double Kcd = exp(-theta_kl * rr_kl);
                double ckcl = ck[kp] * cl[lp] * Kcd;
                gx[0] = ckcl;
            }
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = expi[ip];
                double aj = expj[jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double xij = ri[0] + rjri[0*nsq_per_block] * aj_aij;
                double yij = ri[1] + rjri[1*nsq_per_block] * aj_aij;
                double zij = ri[2] + rjri[2*nsq_per_block] * aj_aij;
                double xkl = rk[0] + rlrk[0*nsq_per_block] * al_akl;
                double ykl = rk[1] + rlrk[1*nsq_per_block] * al_akl;
                double zkl = rk[2] + rlrk[2*nsq_per_block] * al_akl;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                __syncthreads();
                if (gout_id == 0) {
                    Rpq[0*nsq_per_block] = xpq;
                    Rpq[1*nsq_per_block] = ypq;
                    Rpq[2*nsq_per_block] = zpq;
                    double cicj = cicj_cache[ijp*nsq_per_block];
                    gy[0] = cicj / (aij*akl*sqrt(aij+akl));
                }
                double rr = xpq*xpq + ypq*ypq + zpq*zpq;
                double theta = aij * akl / (aij + akl);
                rys_roots_rs(nroots, theta, rr, omega, rw, nsq_per_block, gout_id, gout_stride);
                double s0x, s1x, s2x;
                for (int irys = 0; irys < nroots; ++irys) {
                    __syncthreads();
                    if (gout_id == 0) {
                        gz[0] = rw[(irys*2+1)*nsq_per_block];
                    }
                    double rt = rw[irys*2*nsq_per_block];
                    double rt_aa = rt / (aij + akl);

                    // TRR
                    //for i in range(lij):
                    //    trr(i+1,0) = c0 * trr(i,0) + i*b10 * trr(i-1,0)
                    //for k in range(lkl):
                    //    for i in range(lij+1):
                    //        trr(i,k+1) = c0p * trr(i,k) + k*b01 * trr(i,k-1) + i*b00 * trr(i-1,k)
                    if (lij > 0) {
                        double rt_aij = rt_aa * akl;
                        double b10 = .5/aij * (1 - rt_aij);
                        __syncthreads();
                        // gx(0,n+1) = c0*gx(0,n) + n*b10*gx(0,n-1)
                        for (int n = gout_id; n < 3; n += gout_stride) {
                            double *_gx = g + n * g_size * nsq_per_block;
                            double Rpa = rjri[n*nsq_per_block] * aj_aij;
                            double c0x = Rpa - rt_aij * Rpq[n*nsq_per_block];
                            s0x = _gx[0];
                            s1x = c0x * s0x;
                            _gx[nsq_per_block] = s1x;
                            for (int i = 1; i < lij; ++i) {
                                s2x = c0x * s1x + i * b10 * s0x;
                                _gx[(i+1)*nsq_per_block] = s2x;
                                s0x = s1x;
                                s1x = s2x;
                            }
                        }
                    }

                    if (lkl > 0) {
                        double rt_akl = rt_aa * aij;
                        double b00 = .5 * rt_aa;
                        double b01 = .5/akl * (1 - rt_akl);
                        int lij3 = (lij+1)*3;
                        for (int n = gout_id; n < lij3+gout_id; n += gout_stride) {
                            __syncthreads();
                            int i = n / 3; //for i in range(lij+1):
                            int _ix = n % 3; // TODO: remove _ix for nroots > 2
                            double *_gx = g + (i + _ix * g_size) * nsq_per_block;
                            double Rqc = rlrk[_ix*nsq_per_block] * al_akl;
                            double cpx = Rqc + rt_akl * Rpq[_ix*nsq_per_block];
                            //for i in range(lij+1):
                            //    trr(i,1) = c0p * trr(i,0) + i*b00 * trr(i-1,0)
                            if (n < lij3) {
                                s0x = _gx[0];
                                s1x = cpx * s0x;
                                if (i > 0) {
                                    s1x += i * b00 * _gx[-nsq_per_block];
                                }
                                _gx[stride_k*nsq_per_block] = s1x;
                            }

                            //for k in range(1, lkl):
                            //    for i in range(lij+1):
                            //        trr(i,k+1) = cp * trr(i,k) + k*b01 * trr(i,k-1) + i*b00 * trr(i-1,k)
                            for (int k = 1; k < lkl; ++k) {
                                __syncthreads();
                                if (n < lij3) {
                                    s2x = cpx*s1x + k*b01*s0x;
                                    if (i > 0) {
                                        s2x += i * b00 * _gx[(k*stride_k-1)*nsq_per_block];
                                    }
                                    _gx[(k*stride_k+stride_k)*nsq_per_block] = s2x;
                                    s0x = s1x;
                                    s1x = s2x;
                                }
                            }
                        }
                    }

                    // hrr
                    // g(i,j+1) = rirj * g(i,j) +  g(i+1,j)
                    // g(...,k,l+1) = rkrl * g(...,k,l) + g(...,k+1,l)
                    if (lj > 0) {
                        __syncthreads();
                        if (task_id < ntasks) {
                            int lkl3 = (lkl+1)*3;
                            for (int m = gout_id; m < lkl3; m += gout_stride) {
                                int k = m / 3;
                                int _ix = m % 3;
                                double xjxi = rjri[_ix*nsq_per_block];
                                double *_gx = g + (_ix*g_size + k*stride_k) * nsq_per_block;
                                for (int j = 0; j < lj; ++j) {
                                    int ij = (lij-j) + j*stride_j;
                                    s1x = _gx[ij*nsq_per_block];
                                    for (--ij; ij >= j*stride_j; --ij) {
                                        s0x = _gx[ij*nsq_per_block];
                                        _gx[(ij+stride_j)*nsq_per_block] = s1x - xjxi * s0x;
                                        s1x = s0x;
                                    }
                                }
                            }
                        }
                    }
                    if (ll > 0) {
                        __syncthreads();
                        if (task_id < ntasks) {
                            for (int n = gout_id; n < stride_k*3; n += gout_stride) {
                                int i = n / 3;
                                int _ix = n % 3;
                                double xlxk = rlrk[_ix*nsq_per_block];
                                double *_gx = g + (_ix*g_size + i) * nsq_per_block;
                                for (int l = 0; l < ll; ++l) {
                                    int kl = (lkl-l)*stride_k + l*stride_l;
                                    s1x = _gx[kl*nsq_per_block];
                                    for (kl-=stride_k; kl >= l*stride_l; kl-=stride_k) {
                                        s0x = _gx[kl*nsq_per_block];
                                        _gx[(kl+stride_l)*nsq_per_block] = s1x - xlxk * s0x;
                                        s1x = s0x;
                                    }
                                }
                            }
                        }
                    }

                    __syncthreads();
#pragma unroll
                    for (int n = 0; n < GOUT_WIDTH; ++n) {
                        int ijkl = gout_start + n*gout_stride+gout_id;
                        int kl = ijkl / nfij;
                        int ij = ijkl % nfij;
                        if (kl >= nfkl) break;
                        int addrx = (idx_ij[ij] + idx_kl[kl] * stride_k) * nsq_per_block;
                        int addry = (idy_ij[ij] + idy_kl[kl] * stride_k) * nsq_per_block;
                        int addrz = (idz_ij[ij] + idz_kl[kl] * stride_k) * nsq_per_block;
                        gout[n] += gx[addrx] * gy[addry] * gz[addrz];
                    }
                }
            }
        }

        double *dm = jk.dm;
        double *vj = jk.vj;
        double *vk = jk.vk;
        const bool do_j = (vj != NULL) && (task_id < ntasks);
        const bool do_k = (vk != NULL) && (task_id < ntasks);

        double* j_cache = rw;
        double* j_ij = j_cache;
        double* j_kl = j_ij + nfij * nsq_per_block;
        double* k_cache = do_j ? (j_kl + nfkl * nsq_per_block) : j_cache;
        double* k_ik = k_cache;
        double* k_il = k_ik + nfi * nfk * nsq_per_block;
        double* k_jk = k_il + nfi * nfl * nsq_per_block;
        double* k_jl = k_jk + nfj * nfk * nsq_per_block;
        int jk_cache_size = 0;
        if (do_j) jk_cache_size += nfij + nfkl;
        if (do_k) jk_cache_size += nfi * nfk + nfi * nfl + nfj * nfk + nfj * nfl;

        for (int i_dm = 0; i_dm < jk.n_dm; ++i_dm) {
            __syncthreads();
            for (int i = gout_id; i < jk_cache_size; i += gout_stride)
                j_cache[i * nsq_per_block] = 0;
            __syncthreads();
#pragma unroll
            for (int n = 0; n < GOUT_WIDTH; ++n) {
                int ijkl = (gout_start + n*gout_stride+gout_id);
                int kl = ijkl / nfij;
                int ij = ijkl % nfij;
                if (kl >= nfkl) break;
                double s = gout[n];
                int i = ij % nfi;
                int j = ij / nfi;
                int k = kl % nfk;
                int l = kl / nfk;
                int _i = i + i0;
                int _j = j + j0;
                int _k = k + k0;
                int _l = l + l0;
                if (do_j) {
                    const int _ji = _j*nao+_i;
                    const int _lk = _l*nao+_k;
                    atomicAdd(j_kl + kl * nsq_per_block, s * dm[_ji]);
                    atomicAdd(j_ij + ij * nsq_per_block, s * dm[_lk]);
                }
                if (do_k) {
                    // The order of ik,il,jk,jl is consistent with ij,kl
                    // which is (j * nfi + i) and (l * nfk + k)
                    const int ik = k * nfi + i;
                    const int il = l * nfi + i;
                    const int jk = k * nfj + j;
                    const int jl = l * nfj + j;
                    const int _jl = _j*nao+_l;
                    const int _jk = _j*nao+_k;
                    const int _il = _i*nao+_l;
                    const int _ik = _i*nao+_k;
                    atomicAdd(k_ik + ik * nsq_per_block, s * dm[_jl]);
                    atomicAdd(k_il + il * nsq_per_block, s * dm[_jk]);
                    atomicAdd(k_jk + jk * nsq_per_block, s * dm[_il]);
                    atomicAdd(k_jl + jl * nsq_per_block, s * dm[_ik]);
                }
            }
            __syncthreads();
            if (do_j) {
                for (int ij = gout_id; ij < nfij; ij += gout_stride) {
                    const int i = ij % nfi;
                    const int j = ij / nfi;
                    const int _i = i + i0;
                    const int _j = j + j0;
                    const int _ji = _j*nao+_i;
                    atomicAdd(vj + _ji, j_ij[ij * nsq_per_block]);
                }
                for (int kl = gout_id; kl < nfkl; kl += gout_stride) {
                    const int k = kl % nfk;
                    const int l = kl / nfk;
                    const int _k = k + k0;
                    const int _l = l + l0;
                    const int _lk = _l*nao+_k;
                    atomicAdd(vj + _lk, j_kl[kl * nsq_per_block]);
                }
            }
            if (do_k) {
                for (int ik = gout_id; ik < nfi * nfk; ik += gout_stride) {
                    const int i = ik % nfi;
                    const int k = ik / nfi;
                    const int _i = i + i0;
                    const int _k = k + k0;
                    const int _ik = _i*nao+_k;
                    atomicAdd(vk + _ik, k_ik[ik * nsq_per_block]);
                }
                for (int il = gout_id; il < nfi * nfl; il += gout_stride) {
                    const int i = il % nfi;
                    const int l = il / nfi;
                    const int _i = i + i0;
                    const int _l = l + l0;
                    const int _il = _i*nao+_l;
                    atomicAdd(vk + _il, k_il[il * nsq_per_block]);
                }
                for (int jk = gout_id; jk < nfj * nfk; jk += gout_stride) {
                    const int j = jk % nfj;
                    const int k = jk / nfj;
                    const int _j = j + j0;
                    const int _k = k + k0;
                    const int _jk = _j*nao+_k;
                    atomicAdd(vk + _jk, k_jk[jk * nsq_per_block]);
                }
                for (int jl = gout_id; jl < nfj * nfl; jl += gout_stride) {
                    const int j = jl % nfj;
                    const int l = jl / nfj;
                    const int _j = j + j0;
                    const int _l = l + l0;
                    const int _jl = _j*nao+_l;
                    atomicAdd(vk + _jl, k_jl[jl * nsq_per_block]);
                }
            }
            __syncthreads();

            vj += nao * nao;
            vk += nao * nao;
            dm += nao * nao;
        }
    } }
}

int os_jk_unrolled_lmax = 1;
int os_jk_unrolled_max_order = 0;



__device__
static void eval_gamma_inc_fn(double *f, double t, int m, int sq_id, int block_size)
{
    if (t < EPS_FLOAT64) {
        f[sq_id] = 1.;
        for (int i = 1; i <= m; i++) {
            f[sq_id + i*block_size] = 1./(2*i+1);
        }
    } else if (m > 0 && t < m*.5+.5) {
        double bi = m + .5;
        double e = .5 * exp(-t);
        double x = e;
        double s = e;
        double tol = EPS_FLOAT64 * e;
        while (x > tol) {
            bi += 1.;
            x *= t / bi;
            s += x;
        }
        double b = m + 0.5;
        double fval = s / b;
        f[sq_id + m*block_size] = fval;
        for (int i = m-1; i >= 0; i--) {
            b -= 1.;
            fval = (e + t * fval) / b;
            f[sq_id + i*block_size] = fval;
        }
    } else {
        double tt = sqrt(t);
        double fval = SQRTPIE4 / tt * erf(tt);
        f[sq_id] = fval;
        if (m > 0) {
            double e = .5 * exp(-t);
            double b = 1. / t;
            double b1 = .5;
            for (int i = 1; i <= m; i++) {
                fval = b * (b1 * fval - e);
                f[sq_id + i*block_size] = fval;
                b1 += 1.;
            }
        }
    }
}


__device__ static
void _os_jk_0000(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                ShellQuartet *shl_quartet_idx, int ntasks, int ish0, int jsh0)
{
    int sq_id = threadIdx.x + blockDim.x * threadIdx.y;
    int nsq_per_block = blockDim.x * blockDim.y;
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    int kprim = bounds.kprim;
    int lprim = bounds.lprim;
    int *ao_loc = envs.ao_loc;
    int nbas = envs.nbas;
    int nao = ao_loc[nbas];
    int *bas = envs.bas;
    double *env = envs.env;
    double omega = env[PTR_RANGE_OMEGA];
    extern __shared__ double Rpa_cicj[];
    double *gamma_inc = Rpa_cicj + iprim*jprim*TILE2*4;
    int t_id = threadIdx.y * blockDim.x + threadIdx.x;
    for (int n = t_id; n < iprim*jprim*TILE2; n += nsq_per_block) {
        int ijp = n / TILE2;
        int sh_ij = n % TILE2;
        int ish = ish0 + sh_ij / TILE;
        int jsh = jsh0 + sh_ij % TILE;
        int ip = ijp / jprim;
        int jp = ijp % jprim;
        double *expi = env + bas[ish*BAS_SLOTS+PTR_EXP];
        double *expj = env + bas[jsh*BAS_SLOTS+PTR_EXP];
        double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
        double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
        double *ri = env + bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        double *rj = env + bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        double ai = expi[ip];
        double aj = expj[jp];
        double aij = ai + aj;
        double aj_aij = aj / aij;
        double xjxi = rj[0] - ri[0];
        double yjyi = rj[1] - ri[1];
        double zjzi = rj[2] - ri[2];
        double *Rpa = Rpa_cicj + ijp * TILE2*4;
        Rpa[sh_ij+0*TILE2] = xjxi * aj_aij;
        Rpa[sh_ij+1*TILE2] = yjyi * aj_aij;
        Rpa[sh_ij+2*TILE2] = zjzi * aj_aij;
        double theta_ij = ai * aj / aij;
        double Kab = exp(-theta_ij * (xjxi*xjxi+yjyi*yjyi+zjzi*zjzi));
        Rpa[sh_ij+3*TILE2] = ci[ip] * cj[jp] * Kab;
    }
    double gout0;
    double val;
    double *dm, *vj, *vk;

    for (int task0 = 0; task0 < ntasks; task0 += nsq_per_block) {
        __syncthreads();
        int task_id = task0 + sq_id;
        double fac_sym = PI_FAC;
        ShellQuartet sq;
        if (task_id >= ntasks) {
            // To avoid __syncthreads blocking blocking idle warps, all remaining
            // threads compute a valid shell quartet with zero normalization factor
            sq = shl_quartet_idx[0];
            fac_sym = 0.;
        } else {
            sq = shl_quartet_idx[task_id];
        }
        int ish = sq.i;
        int jsh = sq.j;
        int ksh = sq.k;
        int lsh = sq.l;
        int sh_ij = (ish % TILE) * TILE + (jsh % TILE);
        if (ish == jsh) fac_sym *= .5;
        if (ksh == lsh) fac_sym *= .5;
        if (ish*nbas+jsh == ksh*nbas+lsh) fac_sym *= .5;
        int i0 = ao_loc[ish];
        int j0 = ao_loc[jsh];
        int k0 = ao_loc[ksh];
        int l0 = ao_loc[lsh];
        double *expi = env + bas[ish*BAS_SLOTS+PTR_EXP];
        double *expj = env + bas[jsh*BAS_SLOTS+PTR_EXP];
        double *expk = env + bas[ksh*BAS_SLOTS+PTR_EXP];
        double *expl = env + bas[lsh*BAS_SLOTS+PTR_EXP];
        double *ck = env + bas[ksh*BAS_SLOTS+PTR_COEFF];
        double *cl = env + bas[lsh*BAS_SLOTS+PTR_COEFF];
        double *ri = env + bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        double *rk = env + bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        double *rl = env + bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
    
        gout0 = 0;
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = expk[kp];
            double al = expl[lp];
            double akl = ak + al;
            double al_akl = al / akl;
            double xlxk = rl[0] - rk[0];
            double ylyk = rl[1] - rk[1];
            double zlzk = rl[2] - rk[2];
            double theta_kl = ak * al / akl;
            double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
            double ckcl = fac_sym * ck[kp] * cl[lp] * Kcd;
            double xqc = xlxk * al_akl;
            double yqc = ylyk * al_akl;
            double zqc = zlzk * al_akl;
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = expi[ip];
                double aj = expj[jp];
                double aij = ai + aj;
                double *Rpa = Rpa_cicj + ijp * TILE2*4;
                double cicj = Rpa[sh_ij+3*TILE2];
                double fac = cicj * ckcl / (aij*akl*sqrt(aij+akl));
                double xpa = Rpa[sh_ij+0*TILE2];
                double ypa = Rpa[sh_ij+1*TILE2];
                double zpa = Rpa[sh_ij+2*TILE2];
                double xij = ri[0] + xpa; // (ai*xi+aj*xj)/aij
                double yij = ri[1] + ypa;
                double zij = ri[2] + zpa;
                double xkl = rk[0] + xqc;
                double ykl = rk[1] + yqc;
                double zkl = rk[2] + zqc;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                double theta = aij * akl / (aij + akl);
                double theta_rr = theta * rr;
                if (omega == 0) {
                    eval_gamma_inc_fn(gamma_inc, theta_rr, 0, sq_id, nsq_per_block);
                } else if (omega > 0) {
                    double theta_fac = omega * omega / (omega * omega + theta);
                    eval_gamma_inc_fn(gamma_inc, theta_fac*theta_rr, 0, sq_id, nsq_per_block);
                    double scale = sqrt(theta_fac);
                    for (int n = 0 ; n <= 0; ++n) {
                        gamma_inc[sq_id+n*nsq_per_block] *= scale;
                        scale *= theta_fac;
                    }
                } else { // omega < 0
                    eval_gamma_inc_fn(gamma_inc, theta_rr, 0, sq_id, nsq_per_block);
                    double theta_fac = omega * omega / (omega * omega + theta);
                    double *gamma_inc1 = gamma_inc + nsq_per_block * 1;
                    eval_gamma_inc_fn(gamma_inc1, theta_fac*theta_rr, 0, sq_id, nsq_per_block);
                    __syncthreads();
                    double scale = sqrt(theta_fac);
                    for (int n = 0 ; n <= 0; ++n) {
                        gamma_inc[sq_id+n*nsq_per_block] -= scale * gamma_inc1[sq_id+n*nsq_per_block];
                        scale *= theta_fac;
                    }
                }
                __syncthreads();
                if (task_id < ntasks) {
                    double vrr_0_000 = fac * gamma_inc[sq_id+0*nsq_per_block];
                    gout0 += vrr_0_000;
                }
            }
        }
        if (task_id < ntasks) {
            dm = jk.dm;
            vj = jk.vj;
            vk = jk.vk;
            int do_j = vj != NULL;
            int do_k = vk != NULL;
            for (int i_dm = 0; i_dm < jk.n_dm; ++i_dm) {
                if (do_j) {
                    val = 0;
                    val += gout0 * dm[(l0+0)*nao+(k0+0)];
                    atomicAdd(vj+(i0+0)*nao+(j0+0), val);
                    val = 0;
                    val += gout0 * dm[(j0+0)*nao+(i0+0)];
                    atomicAdd(vj+(k0+0)*nao+(l0+0), val);
                    vj += nao * nao;
                }
                if (do_k) {
                    val = 0;
                    val += gout0 * dm[(j0+0)*nao+(k0+0)];
                    atomicAdd(vk+(i0+0)*nao+(l0+0), val);
                    val = 0;
                    val += gout0 * dm[(i0+0)*nao+(k0+0)];
                    atomicAdd(vk+(j0+0)*nao+(l0+0), val);
                    val = 0;
                    val += gout0 * dm[(j0+0)*nao+(l0+0)];
                    atomicAdd(vk+(i0+0)*nao+(k0+0), val);
                    val = 0;
                    val += gout0 * dm[(i0+0)*nao+(l0+0)];
                    atomicAdd(vk+(j0+0)*nao+(k0+0), val);
                    vk += nao * nao;
                }
                dm += nao * nao;
            }
        }
    }
}
#if CUDA_VERSION >= 12040
__global__ __maxnreg__(128)
#else
__global__
#endif
void os_jk_0000(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                ShellQuartet *pool, uint32_t *batch_head)
{
    int b_id = blockIdx.x;
    int t_id = threadIdx.y * blockDim.x + threadIdx.x;
    ShellQuartet *shl_quartet_idx = pool + b_id * QUEUE_DEPTH;
    __shared__ int batch_id;
    if (t_id == 0) {
        batch_id = atomicAdd(batch_head, 1);
    }
    __syncthreads();
    int nbatches_kl = (bounds.ntile_kl_pairs + TILES_IN_BATCH - 1) / TILES_IN_BATCH;
    int nbatches = bounds.ntile_ij_pairs * nbatches_kl;
    while (batch_id < nbatches) {
        int batch_ij = batch_id / nbatches_kl;
        int batch_kl = batch_id % nbatches_kl;
        int nbas = envs.nbas;
        double omega = envs.env[PTR_RANGE_OMEGA];
        int ntasks;
        if (omega >= 0) {
            ntasks = _fill_jk_tasks(shl_quartet_idx, envs, jk, bounds,
                                    batch_ij, batch_kl);
        } else {
            ntasks = _fill_sr_jk_tasks(shl_quartet_idx, envs, jk, bounds,
                                       batch_ij, batch_kl);
        }
        if (ntasks > 0) {
            int tile_ij = bounds.tile_ij_mapping[batch_ij];
            int nbas_tiles = nbas / TILE;
            int tile_i = tile_ij / nbas_tiles;
            int tile_j = tile_ij % nbas_tiles;
            int ish0 = tile_i * TILE;
            int jsh0 = tile_j * TILE;
            _os_jk_0000(envs, jk, bounds, shl_quartet_idx, ntasks, ish0, jsh0);
        }
        if (t_id == 0) {
            batch_id = atomicAdd(batch_head, 1);
            atomicAdd(batch_head+1, ntasks);
        }
        __syncthreads();
    }
}

int os_jk_unrolled(RysIntEnvVars *envs, JKMatrix *jk, BoundsInfo *bounds,
                   ShellQuartet *pool, uint32_t *batch_head,
                   int *scheme, int workers, double omega)
{
    int li = bounds->li;
    int lj = bounds->lj;
    int lk = bounds->lk;
    int ll = bounds->ll;
    int threads = scheme[0] * scheme[1];
    int iprim = bounds->iprim;
    int jprim = bounds->jprim;
    int ij_prims = iprim * jprim;
    int order = li + lj + lk + ll;
    int buflen = (order + 1) * threads + ij_prims*TILE2*4;
    if (omega < 0) {
        buflen += (order + 1) * threads;
    }
    int ijkl = li*8 + lj*4 + lk*2 + ll;
    switch (ijkl) {
    case 0: os_jk_0000<<<workers, threads, buflen*sizeof(double)>>>(*envs, *jk, *bounds, pool, batch_head); break;
    default: return 1;
    }
    return 0;
}



__global__
void rys_jk_kernel(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                   ShellQuartet *pool, uint32_t *batch_head)
{
    int b_id = blockIdx.x;
    int t_id = threadIdx.y * blockDim.x + threadIdx.x;
    ShellQuartet *shl_quartet_idx = pool + b_id * QUEUE_DEPTH;
    extern __shared__ int batch_id[];
    if (t_id == 0) {
        batch_id[0] = atomicAdd(batch_head, 1);
    }
    __syncthreads();
    int nbatches_kl = (bounds.ntile_kl_pairs + TILES_IN_BATCH - 1) / TILES_IN_BATCH;
    int nbatches = bounds.ntile_ij_pairs * nbatches_kl;
    while (batch_id[0] < nbatches) {
        int batch_ij = batch_id[0] / nbatches_kl;
        int batch_kl = batch_id[0] % nbatches_kl;
        double omega = envs.env[PTR_RANGE_OMEGA];
        int ntasks;
        if (omega >= 0) {
            ntasks = _fill_jk_tasks(shl_quartet_idx, envs, jk, bounds,
                                    batch_ij, batch_kl);
        } else {
            ntasks = _fill_sr_jk_tasks(shl_quartet_idx, envs, jk, bounds,
                                       batch_ij, batch_kl);
        }
        if (ntasks > 0) {
            rys_jk_general(envs, jk, bounds, shl_quartet_idx, ntasks);
            __syncthreads();
        }
        if (t_id == 0) {
            batch_id[0] = atomicAdd(batch_head, 1);
            atomicAdd(batch_head+1, ntasks);
        }
        __syncthreads();
    }
}

