                    gout27 += hrr_1110x * hrr_0001y * wt;
                    double hrr_0110x = trr_11x - xjxi * trr_01x;
                    double hrr_1001y = trr_11y - ylyk * trr_10y;
                    gout28 += hrr_0110x * hrr_1001y * wt;
                    gout29 += hrr_0110x * hrr_0001y * trr_10z;
