                    val += gout15 * dm[(j0+0)*nao+(i0+3)];
                    val += gout16 * dm[(j0+0)*nao+(i0+4)];
                    val += gout17 * dm[(j0+0)*nao+(i0+5)];
                    atomicAdd(vj+(k0+2)*nao+(l0+0), val);
