                    val = 0;
                    val += gout14 * dm[(j0+1)*nao+(l0+2)];
                    val += gout8 * dm[(j0+2)*nao+(l0+1)];
                    atomicAdd(vk+(i0+5)*nao+(k0+0), val);
                    val = 0;
                    val += gout2 * dm[(j0+0)*nao+(l0+0)];
                    val += gout17 * dm[(j0+2)*nao+(l0+2)];
                    atomicAdd(vk+(i0+5)*nao+(k0+1), val);
