                    val += gout6 * dm[(j0+0)*nao+(l0+0)];
                    val += gout16 * dm[(j0+1)*nao+(l0+0)];
                    val += gout26 * dm[(j0+2)*nao+(l0+0)];
                    atomicAdd(vk+(i0+6)*nao+(k0+0), val);
                    val = 0;
                    val += gout7 * dm[(j0+0)*nao+(l0+0)];
                    val += gout17 * dm[(j0+1)*nao+(l0+0)];
                    val += gout27 * dm[(j0+2)*nao+(l0+0)];
                    atomicAdd(vk+(i0+7)*nao+(k0+0), val);
                    val = 0;
                    val += gout8 * dm[(j0+0)*nao+(l0+0)];
                    val += gout18 * dm[(j0+1)*nao+(l0+0)];
                    val += gout28 * dm[(j0+2)*nao+(l0+0)];
                    atomicAdd(vk+(i0+8)*nao+(k0+0), val);
                    val = 0;
                    val += gout9 * dm[(j0+0)*nao+(l0+0)];
                    val += gout19 * dm[(j0+1)*nao+(l0+0)];
                    val += gout29 * dm[(j0+2)*nao+(l0+0)];
                    atomicAdd(vk+(i0+9)*nao+(k0+0), val);
                    val = 0;
                    val += gout0 * dm[(i0+0)*nao+(l0+0)];
                    val += gout1 * dm[(i0+1)*nao+(l0+0)];
                    val += gout2 * dm[(i0+2)*nao+(l0+0)];
                    val += gout3 * dm[(i0+3)*nao+(l0+0)];
                    val += gout4 * dm[(i0+4)*nao+(l0+0)];
                    val += gout5 * dm[(i0+5)*nao+(l0+0)];
                    val += gout6 * dm[(i0+6)*nao+(l0+0)];
                    val += gout7 * dm[(i0+7)*nao+(l0+0)];
                    val += gout8 * dm[(i0+8)*nao+(l0+0)];
                    val += gout9 * dm[(i0+9)*nao+(l0+0)];
                    atomicAdd(vk+(j0+0)*nao+(k0+0), val);
                    val = 0;
                    val += gout10 * dm[(i0+0)*nao+(l0+0)];
                    val += gout11 * dm[(i0+1)*nao+(l0+0)];
                    val += gout12 * dm[(i0+2)*nao+(l0+0)];
                    val += gout13 * dm[(i0+3)*nao+(l0+0)];
                    val += gout14 * dm[(i0+4)*nao+(l0+0)];
                    val += gout15 * dm[(i0+5)*nao+(l0+0)];
                    val += gout16 * dm[(i0+6)*nao+(l0+0)];
                    val += gout17 * dm[(i0+7)*nao+(l0+0)];
                    val += gout18 * dm[(i0+8)*nao+(l0+0)];
                    val += gout19 * dm[(i0+9)*nao+(l0+0)];
                    atomicAdd(vk+(j0+1)*nao+(k0+0), val);
                    val = 0;
                    val += gout20 * dm[(i0+0)*nao+(l0+0)];
                    val += gout21 * dm[(i0+1)*nao+(l0+0)];
                    val += gout22 * dm[(i0+2)*nao+(l0+0)];
                    val += gout23 * dm[(i0+3)*nao+(l0+0)];
                    val += gout24 * dm[(i0+4)*nao+(l0+0)];
                    val += gout25 * dm[(i0+5)*nao+(l0+0)];
                    val += gout26 * dm[(i0+6)*nao+(l0+0)];
                    val += gout27 * dm[(i0+7)*nao+(l0+0)];
                    val += gout28 * dm[(i0+8)*nao+(l0+0)];
                    val += gout29 * dm[(i0+9)*nao+(l0+0)];
                    atomicAdd(vk+(j0+2)*nao+(k0+0), val);
                    vk += nao * nao;
                }
                dm += nao * nao;
            }
        }
    }
}
__global__
static void rys_jk_3100(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                ShellQuartet *pool, uint32_t *batch_head)
{
    int b_id = blockIdx.x;
    int t_id = threadIdx.x + blockDim.x * threadIdx.y;
    ShellQuartet *shl_quartet_idx = pool + b_id * QUEUE_DEPTH;
    extern __shared__ int batch_id[];
    if (t_id == 0) {
        batch_id[0] = atomicAdd(batch_head, 1);
    }
    __syncthreads();
    int nbatches_kl = (bounds.ntile_kl_pairs + TILES_IN_BATCH - 1) / TILES_IN_BATCH;
    int nbatches = bounds.ntile_ij_pairs * nbatches_kl;
    while (batch_id[0] < nbatches) {
        int batch_ij = batch_id[0] / nbatches_kl;
        int batch_kl = batch_id[0] % nbatches_kl;
        double omega = envs.env[PTR_RANGE_OMEGA];
        int ntasks;
        if (omega >= 0) {
            ntasks = _fill_jk_tasks(shl_quartet_idx, envs, jk, bounds,
                                    batch_ij, batch_kl);
        } else {
            ntasks = _fill_sr_jk_tasks(shl_quartet_idx, envs, jk, bounds,
                                       batch_ij, batch_kl);
        }
        if (ntasks > 0) {
            int tile_ij = bounds.tile_ij_mapping[batch_ij];
            int nbas = envs.nbas;
            int nbas_tiles = nbas / TILE;
            int tile_i = tile_ij / nbas_tiles;
            int tile_j = tile_ij % nbas_tiles;
            int ish0 = tile_i * TILE;
            int jsh0 = tile_j * TILE;
            _rys_jk_3100(envs, jk, bounds, shl_quartet_idx, ntasks, ish0, jsh0);
            __syncthreads();
        }
        if (t_id == 0) {
            batch_id[0] = atomicAdd(batch_head, 1);
            atomicAdd(batch_head+1, ntasks);
        }
        __syncthreads();
    }
}

__device__ static
void _rys_jk_3110(RysIntEnvVars envs, JKMatrix jk, BoundsInfo bounds,
                ShellQuartet *shl_quartet_idx, int ntasks, int ish0, int jsh0)
{
    int sq_id = threadIdx.x;
    int gout_id = threadIdx.y;
    int iprim = bounds.iprim;
    int jprim = bounds.jprim;
    int kprim = bounds.kprim;
    int lprim = bounds.lprim;
    int nroots = bounds.nroots;
    int *ao_loc = envs.ao_loc;
    int nbas = envs.nbas;
    int nao = ao_loc[nbas];
    int *bas = envs.bas;
    double *env = envs.env;
    extern __shared__ double cicj_cache[];
    double *rw = cicj_cache + iprim*jprim*TILE2 + sq_id;
    double *gx = rw + nroots * 128;
    double *gy = gx + 1024;
    double *gz = gy + 1024;
    double *rjri = gz + 1024;
    double *rlrk = rjri + 192;
    double *Rpq = rlrk + 192;

    int thread_id = 64 * gout_id + sq_id;
    int threads = 256;
    for (int n = thread_id; n < iprim*jprim*TILE2; n += threads) {
        int ijp = n / TILE2;
        int sh_ij = n % TILE2;
        int ish = ish0 + sh_ij / TILE;
        int jsh = jsh0 + sh_ij % TILE;
        int ip = ijp / jprim;
        int jp = ijp % jprim;
        double *expi = env + bas[ish*BAS_SLOTS+PTR_EXP];
        double *expj = env + bas[jsh*BAS_SLOTS+PTR_EXP];
        double *ci = env + bas[ish*BAS_SLOTS+PTR_COEFF];
        double *cj = env + bas[jsh*BAS_SLOTS+PTR_COEFF];
        double *ri = env + bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        double *rj = env + bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        double ai = expi[ip];
        double aj = expj[jp];
        double aij = ai + aj;
        double xjxi = rj[0] - ri[0];
        double yjyi = rj[1] - ri[1];
        double zjzi = rj[2] - ri[2];
        double theta_ij = ai * aj / aij;
        double Kab = exp(-theta_ij * (xjxi*xjxi+yjyi*yjyi+zjzi*zjzi));
        cicj_cache[sh_ij+ijp*TILE2] = ci[ip] * cj[jp] * Kab;
    }
    double gout0;
    double gout1;
    double gout2;
    double gout3;
    double gout4;
    double gout5;
    double gout6;
    double gout7;
    double gout8;
    double gout9;
    double gout10;
    double gout11;
    double gout12;
    double gout13;
    double gout14;
    double gout15;
    double gout16;
    double gout17;
    double gout18;
    double gout19;
    double gout20;
    double gout21;
    double gout22;
    double s0, s1, s2;
    double val;
    double *dm, *vj, *vk;

    for (int task0 = 0; task0 < ntasks; task0 += 64) {
        __syncthreads();
        int task_id = task0 + sq_id;
        double fac_sym = PI_FAC;
        ShellQuartet sq;
        if (task_id >= ntasks) {
            // To avoid __syncthreads blocking blocking idle warps, all remaining
            // threads compute a valid shell quartet with zero normalization factor
            sq = shl_quartet_idx[0];
            fac_sym = 0.;
        } else {
            sq = shl_quartet_idx[task_id];
        }
        int ish = sq.i;
        int jsh = sq.j;
        int ksh = sq.k;
        int lsh = sq.l;
        int sh_ij = (ish % TILE) * TILE + (jsh % TILE);
        if (ish == jsh) fac_sym *= .5;
        if (ksh == lsh) fac_sym *= .5;
        if (ish*nbas+jsh == ksh*nbas+lsh) fac_sym *= .5;
        int i0 = ao_loc[ish];
        int j0 = ao_loc[jsh];
        int k0 = ao_loc[ksh];
        int l0 = ao_loc[lsh];
        double *expi = env + bas[ish*BAS_SLOTS+PTR_EXP];
        double *expj = env + bas[jsh*BAS_SLOTS+PTR_EXP];
        double *expk = env + bas[ksh*BAS_SLOTS+PTR_EXP];
        double *expl = env + bas[lsh*BAS_SLOTS+PTR_EXP];
        double *ck = env + bas[ksh*BAS_SLOTS+PTR_COEFF];
        double *cl = env + bas[lsh*BAS_SLOTS+PTR_COEFF];
        double *ri = env + bas[ish*BAS_SLOTS+PTR_BAS_COORD];
        double *rj = env + bas[jsh*BAS_SLOTS+PTR_BAS_COORD];
        double *rk = env + bas[ksh*BAS_SLOTS+PTR_BAS_COORD];
        double *rl = env + bas[lsh*BAS_SLOTS+PTR_BAS_COORD];
        if (gout_id == 0) {
            double xjxi = rj[0] - ri[0];
            double yjyi = rj[1] - ri[1];
            double zjzi = rj[2] - ri[2];
            double xlxk = rl[0] - rk[0];
            double ylyk = rl[1] - rk[1];
            double zlzk = rl[2] - rk[2];
            rjri[0] = xjxi;
            rjri[64] = yjyi;
            rjri[128] = zjzi;
            rlrk[0] = xlxk;
            rlrk[64] = ylyk;
            rlrk[128] = zlzk;
        }
        
        gout0 = 0;
        gout1 = 0;
        gout2 = 0;
        gout3 = 0;
        gout4 = 0;
        gout5 = 0;
        gout6 = 0;
        gout7 = 0;
        gout8 = 0;
        gout9 = 0;
        gout10 = 0;
        gout11 = 0;
        gout12 = 0;
        gout13 = 0;
        gout14 = 0;
        gout15 = 0;
        gout16 = 0;
        gout17 = 0;
        gout18 = 0;
        gout19 = 0;
        gout20 = 0;
        gout21 = 0;
        gout22 = 0;
        for (int klp = 0; klp < kprim*lprim; ++klp) {
            int kp = klp / lprim;
            int lp = klp % lprim;
            double ak = expk[kp];
            double al = expl[lp];
            double akl = ak + al;
            double al_akl = al / akl;
            __syncthreads();
            if (gout_id == 0) {
                double xlxk = rlrk[0];
                double ylyk = rlrk[64];
                double zlzk = rlrk[128];
                double theta_kl = ak * al_akl;
                double Kcd = exp(-theta_kl * (xlxk*xlxk+ylyk*ylyk+zlzk*zlzk));
                double ckcl = fac_sym * ck[kp] * cl[lp] * Kcd;
                gx[0] = ckcl;
            }
            for (int ijp = 0; ijp < iprim*jprim; ++ijp) {
                int ip = ijp / jprim;
                int jp = ijp % jprim;
                double ai = expi[ip];
                double aj = expj[jp];
                double aij = ai + aj;
                double aj_aij = aj / aij;
                double xij = ri[0] + rjri[0] * aj_aij;
                double yij = ri[1] + rjri[64] * aj_aij;
                double zij = ri[2] + rjri[128] * aj_aij;
                double xkl = rk[0] + rlrk[0] * al_akl;
                double ykl = rk[1] + rlrk[64] * al_akl;
                double zkl = rk[2] + rlrk[128] * al_akl;
                double xpq = xij - xkl;
                double ypq = yij - ykl;
                double zpq = zij - zkl;
                __syncthreads();
                if (gout_id == 0) {
                    Rpq[0] = xpq;
                    Rpq[64] = ypq;
                    Rpq[128] = zpq;
                    double cicj = cicj_cache[sh_ij+ijp*TILE2];
                    gy[0] = cicj / (aij*akl*sqrt(aij+akl));
                }
                double theta = aij * akl / (aij + akl);
                double rr = xpq * xpq + ypq * ypq + zpq * zpq;
                double omega = env[PTR_RANGE_OMEGA];
                __syncthreads();
                rys_roots_rs(nroots, theta, rr, omega, rw, 64, gout_id, 4);
                for (int irys = 0; irys < nroots; ++irys) {
                    __syncthreads();
                    double rt = rw[irys*128];
                    double rt_aa = rt / (aij + akl);
                    double rt_aij = rt_aa * akl;
                    double b10 = .5/aij * (1 - rt_aij);
                    double rt_akl = rt_aa * aij;
                    double b00 = .5 * rt_aa;
                    for (int n = gout_id; n < 3; n += 4) {
                        if (n == 2) {
                            gz[0] = rw[irys*128+64];
                        }
                        double *_gx = gx + n * 1024;
                        double xjxi = rjri[n*64];
                        double Rpa = xjxi * aj_aij;
                        double c0x = Rpa - rt_aij * Rpq[n*64];
                        s0 = _gx[0];
                        s1 = c0x * s0;
                        _gx[64] = s1;
                        s2 = c0x * s1 + 1 * b10 * s0;
                        _gx[128] = s2;
                        s0 = s1;
                        s1 = s2;
                        s2 = c0x * s1 + 2 * b10 * s0;
                        _gx[192] = s2;
                        s0 = s1;
                        s1 = s2;
                        s2 = c0x * s1 + 3 * b10 * s0;
                        _gx[256] = s2;
                        double xlxk = rlrk[n*64];
                        double Rqc = xlxk * al_akl;
                        double cpx = Rqc + rt_akl * Rpq[n*64];
                        s0 = _gx[0];
                        s1 = cpx * s0;
                        _gx[512] = s1;
                        s0 = _gx[64];
                        s1 = cpx * s0;
                        s1 += 1 * b00 * _gx[0];
                        _gx[576] = s1;
                        s0 = _gx[128];
                        s1 = cpx * s0;
                        s1 += 2 * b00 * _gx[64];
                        _gx[640] = s1;
                        s0 = _gx[192];
                        s1 = cpx * s0;
                        s1 += 3 * b00 * _gx[128];
                        _gx[704] = s1;
                        s0 = _gx[256];
                        s1 = cpx * s0;
                        s1 += 4 * b00 * _gx[192];
                        _gx[768] = s1;
                        s1 = _gx[256];
                        s0 = _gx[192];
                        _gx[448] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[128];
                        _gx[384] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[64];
                        _gx[320] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[0];
                        _gx[256] = s1 - xjxi * s0;
                        s1 = _gx[768];
                        s0 = _gx[704];
                        _gx[960] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[640];
                        _gx[896] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[576];
                        _gx[832] = s1 - xjxi * s0;
                        s1 = s0;
                        s0 = _gx[512];
                        _gx[768] = s1 - xjxi * s0;
                    }
                    __syncthreads();
                    switch (gout_id) {
                    case 0:
                    gout0 += gx[960] * gy[0] * gz[0];
                    gout1 += gx[832] * gy[64] * gz[64];
                    gout2 += gx[768] * gy[64] * gz[128];
                    gout3 += gx[640] * gy[256] * gz[64];
                    gout4 += gx[512] * gy[448] * gz[0];
                    gout5 += gx[704] * gy[0] * gz[256];
                    gout6 += gx[576] * gy[64] * gz[320];
                    gout7 += gx[512] * gy[64] * gz[384];
                    gout8 += gx[384] * gy[512] * gz[64];
                    gout9 += gx[256] * gy[704] * gz[0];
                    gout10 += gx[192] * gy[768] * gz[0];
