                    double hrr_1100z = trr_20z - zjzi * trr_10z;
                    gout22 += hrr_2100x * fac * hrr_1100z;
                    gout23 += hrr_1100x * trr_20y * hrr_0100z;
                    gout24 += hrr_1100x * trr_10y * hrr_1100z;
